import{_ as a,c as e,o as l,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"スキル管理: 利用可能なスキルの照会 | opencode-agent-skills","description":"get_available_skills ツールの使用方法を学びます。検索、名前空間、フィルタリングでスキルを素早く見つけ、スキル発見と管理の主要機能を習得します。","frontmatter":{"title":"スキル管理: 利用可能なスキルの照会 | opencode-agent-skills","sidebarTitle":"スキルを素早く見つける","subtitle":"スキル管理: 利用可能なスキルの照会","description":"get_available_skills ツールの使用方法を学びます。検索、名前空間、フィルタリングでスキルを素早く見つけ、スキル発見と管理の主要機能を習得します。","tags":["スキル管理","ツールの活用","名前空間"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"ja/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"ja/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),i={name:"ja/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function t(p,s,o,c,d,r){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="利用可能なスキルの照会と一覧表示" tabindex="-1">利用可能なスキルの照会と一覧表示 <a class="header-anchor" href="#利用可能なスキルの照会と一覧表示" aria-label="Permalink to &quot;利用可能なスキルの照会と一覧表示&quot;">​</a></h1><h2 id="本レッスンでできること" tabindex="-1">本レッスンでできること <a class="header-anchor" href="#本レッスンでできること" aria-label="Permalink to &quot;本レッスンでできること&quot;">​</a></h2><ul><li><code>get_available_skills</code> ツールを使用して、利用可能なすべてのスキルを一覧表示する</li><li>検索クエリを使用して特定のスキルをフィルタリングする</li><li>名前空間（<code>project:skill-name</code> など）を使用してスキルを正確に特定する</li><li>スキルのソースと実行可能スクリプトリストを識別する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>特定のスキルを使用したいが、その正確な名前を思い出せない。プロジェクト内のスキルであることはわかっているが、どの発見パスにあるかわからない。あるいは、単に現在のプロジェクトでどのようなスキルが利用可能かを素早く確認したい。</p><h2 id="この機能を使う場面" tabindex="-1">この機能を使う場面 <a class="header-anchor" href="#この機能を使う場面" aria-label="Permalink to &quot;この機能を使う場面&quot;">​</a></h2><ul><li><strong>新しいプロジェクトの探索</strong>: 新しいプロジェクトに参加したとき、利用可能なスキルを素早く把握する</li><li><strong>スキル名が不明確</strong>: スキル名の一部や説明しか覚えていない場合、あいまい一致で検索する</li><li><strong>名前空間の衝突</strong>: プロジェクトレベルとユーザーレベルに同名のスキルがあり、どちらを使用するか明確に指定する必要がある</li><li><strong>スクリプトの検索</strong>: スキルディレクトリ下にどのような実行可能スクリプトがあるか知りたい</li></ul><h2 id="核心的なアプローチ" tabindex="-1">核心的なアプローチ <a class="header-anchor" href="#核心的なアプローチ" aria-label="Permalink to &quot;核心的なアプローチ&quot;">​</a></h2><p><code>get_available_skills</code> ツールを使用すると、現在のセッションで利用可能なすべてのスキルを確認できます。プラグインは 6 つの発見パスから自動的にスキルをスキャンします：</p><div class="info custom-block"><p class="custom-block-title">スキル発見の優先順位</p><ol><li><code>.opencode/skills/</code> (プロジェクトレベル OpenCode)</li><li><code>.claude/skills/</code> (プロジェクトレベル Claude)</li><li><code>~/.config/opencode/skills/</code> (ユーザーレベル OpenCode)</li><li><code>~/.claude/skills/</code> (ユーザーレベル Claude)</li><li><code>~/.claude/plugins/cache/</code> (プラグインキャッシュ)</li><li><code>~/.claude/plugins/marketplaces/</code> (インストール済みプラグイン)</li></ol></div><p>同名のスキルは優先順位に従って最初のもののみが保持され、後続のものは無視されます。</p><p>ツールが返す情報には以下が含まれます：</p><ul><li><strong>スキル名</strong></li><li><strong>ソースタグ</strong>（project、user、claude-project など）</li><li><strong>説明</strong></li><li><strong>実行可能スクリプトリスト</strong>（ある場合）</li></ul><div class="tip custom-block"><p class="custom-block-title">名前空間の構文</p><p><code>namespace:skill-name</code> 形式を使用してソースを明示的に指定できます：</p><ul><li><code>project:my-skill</code> - プロジェクトレベル OpenCode スキルを使用（<code>.opencode/skills/</code>）</li><li><code>claude-project:my-skill</code> - プロジェクトレベル Claude スキルを使用（<code>.claude/skills/</code>）</li><li><code>user:my-skill</code> - ユーザーレベル OpenCode スキルを使用（<code>~/.config/opencode/skills/</code>）</li><li><code>claude-user:my-skill</code> - ユーザーレベル Claude スキルを使用（<code>~/.claude/skills/</code>）</li><li><code>claude-plugins:my-skill</code> - Claude プラグイン内のスキルを使用</li></ul></div><h2 id="ハンズオン" tabindex="-1">ハンズオン <a class="header-anchor" href="#ハンズオン" aria-label="Permalink to &quot;ハンズオン&quot;">​</a></h2><h3 id="ステップ-1-利用可能なすべてのスキルを一覧表示" tabindex="-1">ステップ 1: 利用可能なすべてのスキルを一覧表示 <a class="header-anchor" href="#ステップ-1-利用可能なすべてのスキルを一覧表示" aria-label="Permalink to &quot;ステップ 1: 利用可能なすべてのスキルを一覧表示&quot;">​</a></h3><p>OpenCode で AI に直接スキルの一覧を要求します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>列出所有可用的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Git 操作和分支管理助手 [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  单元测试和覆盖率分析工具</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  完整的软件开发工作流</span></span></code></pre></div><p><strong>確認できること</strong>: スキルの一覧が表示され、各スキルは名前、ソースタグ、説明、スクリプトリストを表示します。</p><h3 id="ステップ-2-検索クエリを使用したフィルタリング" tabindex="-1">ステップ 2: 検索クエリを使用したフィルタリング <a class="header-anchor" href="#ステップ-2-検索クエリを使用したフィルタリング" aria-label="Permalink to &quot;ステップ 2: 検索クエリを使用したフィルタリング&quot;">​</a></h3><p>スキル名の一部しか覚えていない場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>查找包含 &quot;docker&quot; 的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>検索はスキル名と説明のキーワードに一致し、<code>*</code> ワイルドカードをサポートします：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>查找以 &quot;test&quot; 开头的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  单元测试和覆盖率分析工具</span></span></code></pre></div><p><strong>確認できること</strong>: クエリ条件に一致するスキルのみが表示されます。</p><h3 id="ステップ-3-あいまい一致の推奨を体験" tabindex="-1">ステップ 3: あいまい一致の推奨を体験 <a class="header-anchor" href="#ステップ-3-あいまい一致の推奨を体験" aria-label="Permalink to &quot;ステップ 3: あいまい一致の推奨を体験&quot;">​</a></h3><p>間違ったスキル名を入力した場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>我想用 docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>No skills found matching &quot;docker-asistant&quot;. Did you mean &quot;docker-helper&quot;?</span></span></code></pre></div><p>プラグインは Levenshtein 距離に基づいて類似度を計算し、最も近いスキル名を自動的に推奨します。</p><p><strong>確認できること</strong>: エラーメッセージと正しいスキル名の推奨が表示されます。</p><h3 id="ステップ-4-名前空間を使用した正確な特定" tabindex="-1">ステップ 4: 名前空間を使用した正確な特定 <a class="header-anchor" href="#ステップ-4-名前空間を使用した正確な特定" aria-label="Permalink to &quot;ステップ 4: 名前空間を使用した正確な特定&quot;">​</a></h3><p>プロジェクトレベルとユーザーレベルの両方に <code>build-helper</code> という名前のスキルがあると仮定します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>列出 build-helper 的详细信息</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  项目特定的构建配置和编译优化 [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>ユーザーがユーザーレベルのスキルを要求する場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>使用 user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  通用构建工具链和持续集成配置 [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>確認できること</strong>: 名前空間プレフィックスを使用して、異なるソースの同名スキルにアクセスできます。</p><h3 id="ステップ-5-実行可能スクリプトの確認" tabindex="-1">ステップ 5: 実行可能スクリプトの確認 <a class="header-anchor" href="#ステップ-5-実行可能スクリプトの確認" aria-label="Permalink to &quot;ステップ 5: 実行可能スクリプトの確認&quot;">​</a></h3><p>スキルディレクトリ下にどのようなスクリプトがあるかを確認します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー入力：</span></span>
<span class="line"><span>docker-helper 有哪些脚本？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>システム応答：</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>スクリプトはスキル情報の角括弧内に表示され、カンマで区切られます。これらのスクリプトは <code>run_skill_script</code> ツールを使用して実行できます。</p><p><strong>確認できること</strong>: スキル名の後に <code>[scripts: スクリプトパス1, スクリプトパス2, ...]</code> 形式のリストが表示されます。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] 利用可能なすべてのスキルを一覧表示できますか？</li><li>[ ] 検索クエリを使用して特定のスキルをフィルタリングできますか？</li><li>[ ] スキルのソースタグの意味を理解していますか（project、user、claude-project など）？</li><li>[ ] スキル名前空間の役割と構文を説明できますか？</li><li>[ ] スキル情報から実行可能スクリプトリストを識別できますか？</li></ul><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><h3 id="トラップ-1-同名スキルの上書き" tabindex="-1">トラップ 1: 同名スキルの上書き <a class="header-anchor" href="#トラップ-1-同名スキルの上書き" aria-label="Permalink to &quot;トラップ 1: 同名スキルの上書き&quot;">​</a></h3><p>プロジェクトレベルとユーザーレベルに同名のスキルがある場合、期待したスキルがロードされないことに困惑するかもしれません。</p><p><strong>原因</strong>: スキルは優先順位に従って発見され、プロジェクトレベルがユーザーレベルより優先され、同名のものは最初のもののみが保持されます。</p><p><strong>解決策</strong>: 名前空間を明示的に指定します。例：<code>user:my-skill</code> ではなく <code>my-skill</code> を使用します。</p><h3 id="トラップ-2-検索の大文字小文字の区別" tabindex="-1">トラップ 2: 検索の大文字小文字の区別 <a class="header-anchor" href="#トラップ-2-検索の大文字小文字の区別" aria-label="Permalink to &quot;トラップ 2: 検索の大文字小文字の区別&quot;">​</a></h3><p>検索クエリは正規表現を使用しますが、<code>i</code> フラグが設定されているため、大文字小文字は区別されません。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># これらの検索は等価</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="トラップ-3-ワイルドカードのエスケープ" tabindex="-1">トラップ 3: ワイルドカードのエスケープ <a class="header-anchor" href="#トラップ-3-ワイルドカードのエスケープ" aria-label="Permalink to &quot;トラップ 3: ワイルドカードのエスケープ&quot;">​</a></h3><p>検索内の <code>*</code> は自動的に <code>.*</code> 正規表現に変換されるため、手動でエスケープする必要はありません：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># &quot;test&quot; で始まるスキルを検索</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 正規表現 /test.*/i と同等</span></span></code></pre></div><h2 id="本レッスンのまとめ" tabindex="-1">本レッスンのまとめ <a class="header-anchor" href="#本レッスンのまとめ" aria-label="Permalink to &quot;本レッスンのまとめ&quot;">​</a></h2><p><code>get_available_skills</code> はスキルエコシステムを探索するツールで、以下をサポートします：</p><ul><li><strong>すべてのスキルの一覧表示</strong>: 引数なしで呼び出す</li><li><strong>検索フィルタリング</strong>: <code>query</code> パラメータを使用して名前と説明に一致させる</li><li><strong>名前空間</strong>: <code>namespace:skill-name</code> 形式で正確に特定する</li><li><strong>あいまい一致の推奨</strong>: スペルミス時に正しい名前を自動的に提示する</li><li><strong>スクリプトリスト</strong>: 実行可能な自動化スクリプトを表示する</li></ul><p>プラグインはセッション開始時に自動的にスキルリストを注入するため、通常はこのツールを手動で呼び出す必要はありません。ただし、以下のシナリオでは非常に役立ちます：</p><ul><li>利用可能なスキルを素早く確認したい場合</li><li>スキルの正確な名前を思い出せない場合</li><li>同名スキルの異なるソースを区別する必要がある場合</li><li>特定のスキルのスクリプトリストを確認したい場合</li></ul><h2 id="次のレッスンの予告" tabindex="-1">次のレッスンの予告 <a class="header-anchor" href="#次のレッスンの予告" aria-label="Permalink to &quot;次のレッスンの予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../loading-skills-into-context/">スキルをセッションコンテキストに読み込む</a></strong> を学習します。</p><p>以下の内容を学びます：</p><ul><li>use_skill ツールを使用してスキルを現在のセッションに読み込む</li><li>スキル内容が XML 形式でコンテキストに注入される仕組みを理解する</li><li>Synthetic Message Injection メカニズム（合成メッセージ注入）を習得する</li><li>セッション圧縮後にスキルがどのように利用可能になるかを理解する</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録: ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録: ソースコード参照&quot;">​</a></h2><details><summary><strong>展開してソースコードの場所を表示</strong></summary><blockquote><p>更新日時: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>GetAvailableSkills ツール定義</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>discoverAllSkills 関数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>resolveSkill 関数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>findClosestMatch 関数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>主要な型</strong>：</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>：スキルソースタグの列挙型</li></ul><p><strong>主要な定数</strong>：</p><ul><li>あいまい一致のしきい値：<code>0.4</code>（<code>utils.ts:124</code>）- 類似度がこの値を下回る場合、推奨を返さない</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>GetAvailableSkills()</code>：フォーマットされたスキルリストを返し、クエリフィルタリングとあいまい一致の推奨をサポート</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>：<code>namespace:skill-name</code> 形式のスキル解析をサポート</li><li><code>findClosestMatch(input: string, candidates: string[])</code>：複数の一致戦略（プレフィックス、包含、編集距離）に基づいて最適な一致を計算</li></ul><p><strong>ビジネスルール</strong>：</p><ul><li>同名スキルは発見順に重複排除され、最初のもののみが保持される（<code>skills.ts:258</code>）</li><li>検索クエリはワイルドカード <code>*</code> をサポートし、自動的に正規表現に変換される（<code>tools.ts:43</code>）</li><li>あいまい一致の推奨はクエリパラメータがあり結果がない場合にのみトリガーされる（<code>tools.ts:49-57</code>）</li></ul></details>`,64)])])}const k=a(i,[["render",t]]);export{u as __pageData,k as default};
